input.command:
cargo update -p generic-array --dry-run 2>&1 | head -10 && echo "--- lockfile req ---" && grep -A2 'name = "generic-array"' /home/wink/data/prgs/rust/vc-x1/Cargo.lock | head -10 && echo "--- block-buffer's req on generic-array ---" && cargo metadata --format-version 1 2>/dev/null | python3 -c "
import json,sys
m = json.load(sys.stdin)
for p in m['packages']:
    if p['name'] in ('block-buffer','digest','crypto-common','typenum'):
        for d in p['dependencies']:
            if d['name'] == 'generic-array':
                print(f\"  {p['name']} v{p['version']} requires generic-array {d['req']}\")
"

